sql:
SELECT genre, COUNT(*) AS number_of_pieces
FROM musical_pieces
GROUP BY genre;

SELECT AVG(duration) AS average_duration
FROM musical_pieces
WHERE period = 'Classicism';

SELECT title
FROM musical_pieces
WHERE duration = (
  SELECT MIN(duration)
  FROM musical_pieces
);

SELECT *
FROM chords
WHERE measure_id = 123;

SELECT title, duration
FROM musical_pieces
ORDER BY duration DESC;

SELECT mp.title, COUNT(mp.updated_date) AS times_updated
FROM musical_pieces mp
GROUP BY mp.piece_id;

SELECT *
FROM access_logs
WHERE piece_id = (SELECT piece_id FROM musical_pieces WHERE title = 'Piano Concerto No. 1');

SELECT title, composer, year_composed
FROM musical_pieces
WHERE piece_id = 1;

SELECT version_description 
FROM analysis_versions 
WHERE version_type = 'draft';
